def generate():
    basedir = os.path.dirname(os.path.abspath(__file__))
    tpl_path = os.path.join(basedir, "docs", "interactive", "_template.html")
    outdir = os.path.join(basedir, "docs", "interactive")
    with open(tpl_path, "r") as f:
        template = f.read()
    for key, system in SYSTEMS.items():
        html = template.replace("__TITLE__", system["title"]).replace("__DATA_JSON__", json.dumps(system["levels"]))
        with open(os.path.join(outdir, f"{key}.html"), "w") as f:
            f.write(html)
        print(f"  ✓ interactive/{key}.html")
    print(f"\n✅ {len(SYSTEMS)} pages generated")

if __name__ == "__main__":
    generate()
